import{_ as o}from"./chunks/dashboard_01.InoLIzPU.js";import{_ as t,o as a,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"仪表板","description":"","frontmatter":{},"headers":[],"relativePath":"zh/getting-started/dashboard.md","filePath":"zh/getting-started/dashboard.md"}'),n={name:"zh/getting-started/dashboard.md"};function l(s,e,c,d,g,h){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="仪表板" tabindex="-1"><i class="ph ph-speedometer"></i> 仪表板 <a class="header-anchor" href="#仪表板" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-speedometer&quot;&gt;&lt;/i&gt; 仪表板&quot;">​</a></h1><p><strong>仪表板 (Dashboard)</strong> 是一个功能强大的游戏内分析器和控制面板。它允许您监控插件的运行情况，分析帧时序，并直接在运行中的构建里手动覆盖缩放器级别。</p><p><img src="'+o+'" alt=""></p><h2 id="如何使用" tabindex="-1">如何使用 <a class="header-anchor" href="#如何使用" aria-label="Permalink to &quot;如何使用&quot;">​</a></h2><p>将 <code>Dashboard.prefab</code> 拖放到您项目中的任何场景。<br> 它会自动将自身设置为 <code>DontDestroyOnLoad</code>，并在场景转换期间保持可用。</p><div class="info custom-block"><p class="custom-block-title">生产构建注意事项</p><p>仪表板与插件核心完全解耦。在发布游戏之前，只需从场景中删除该预制件即可。Unity 的代码剥离 (Code Stripping) 系统将自动从最终构建中移除所有仪表板代码（避免 <code>Resources</code> 文件夹臃肿），从而保持最小的项目权重。WebAP 核心将继续在后台运行。</p></div><h2 id="左侧面板-控制" tabindex="-1"><i class="ph ph-sliders"></i> 左侧面板 (控制) <a class="header-anchor" href="#左侧面板-控制" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-sliders&quot;&gt;&lt;/i&gt; 左侧面板 (控制)&quot;">​</a></h2><p>仪表板的左侧专为与插件进行实时交互而设计。</p><ul><li><strong>Enable Web AP</strong><br> 插件核心的全局开关。如果禁用，自动优化将停止，所有图形参数将恢复为其原始（最大）值。</li><li><strong>Anti Yo-Yo Protection</strong><br> 启用或禁用惩罚锁定。如果禁用，插件可以在没有临时阻塞的情况下增加和减少图形质量。<br><em>(查看详情：<a href="./../advanced/anti-yoyo">Anti Yo-Yo 系统</a>)</em></li><li><strong>Active Scalers</strong><br> 添加到系统中的所有优化模块的列表。 <ul><li><strong>开关 (Toggle):</strong> 动态启用或完全禁用特定的缩放器 (Scaler)。</li><li><strong>滑块 (Slider):</strong> 手动覆盖质量级别 (<code>Override Level</code>)。值为 <code>0</code> 表示最高质量。如果移动滑块，索引器将停止管理此缩放器，允许您直观地评估其对游戏的影响。</li><li><strong>分辨率模式 (Resolution Mode):</strong> <code>分辨率缩放器 (Resolution Scaler)</code> 的独家设置（在 BiRP 模式下）。允许在 <code>原生浏览器缩放 (NativeBrowserScaling)</code> 和 <code>渲染纹理缩放 (RenderTextureScaling)</code> 策略之间动态切换。<br><em>(查看详情：<a href="./../scalers/reference">缩放器参考</a>)</em></li></ul></li></ul><h2 id="右侧面板-分析" tabindex="-1"><i class="ph ph-chart-bar"></i> 右侧面板 (分析) <a class="header-anchor" href="#右侧面板-分析" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-chart-bar&quot;&gt;&lt;/i&gt; 右侧面板 (分析)&quot;">​</a></h2><p>右侧显示原始引擎指标和插件“大脑”的内部逻辑。利用零垃圾回收指数移动平均 (Zero-GC Exponential Moving Average) 算法来平滑图表。</p><h3 id="指标和时序-metrics-timings" tabindex="-1">指标和时序 (Metrics &amp; Timings) <a class="header-anchor" href="#指标和时序-metrics-timings" aria-label="Permalink to &quot;指标和时序 (Metrics &amp; Timings)&quot;">​</a></h3><ul><li><strong>Target Min FPS:</strong> 从您的项目设置中检索的基线性能目标。</li><li><strong>Current FPS:</strong> 具有历史尖峰图的当前帧速率。</li><li><strong>Current Scale / DPI:</strong> 当前分辨率乘数。<code>1.00</code> 表示原生分辨率。较低的值（例如，<code>0.50</code>）表示降低了 3D 世界分辨率以节省 GPU。</li><li><strong>Frame Time / CPU Time:</strong> 通过 <code>FrameTimingManager</code> 收集的精确硬件时序。它们有助于理解 CPU 在帧逻辑上花费了多少实际时间。</li></ul><h3 id="插件大脑-plugin-brain" tabindex="-1">插件大脑 (Plugin Brain) <a class="header-anchor" href="#插件大脑-plugin-brain" aria-label="Permalink to &quot;插件大脑 (Plugin Brain)&quot;">​</a></h3><p>显示决策管道逻辑。<br><em>(查看详情：<a href="./../advanced/how-it-works">工作原理</a>)</em></p><ul><li><strong>Bottleneck:</strong> 识别当前哪个设备子系统存在延迟（<code>CPU</code>、<code>GPU</code>、<code>TargetFrameRate</code> 或 <code>Unknown</code>）。</li><li><strong>Action:</strong> 指示索引器打算做什么（<code>IncreaseQuality</code>、<code>DecreaseQuality</code> 或 <code>Stale</code> — 如果不需要任何操作）。</li><li><strong>Status (Action 下方):</strong> 系统状态：<code>Monitoring...</code>（评估帧）、<code>Cooldown</code>（图形更改后等待稳定）或 <code>Penalty Lockout</code>（Anti Yo-Yo 惩罚处于活动状态）。</li></ul><h3 id="活动-active" tabindex="-1">活动 (Active) <a class="header-anchor" href="#活动-active" aria-label="Permalink to &quot;活动 (Active)&quot;">​</a></h3><ul><li>目前级别被系统 <strong>降低</strong> 以节省性能的缩放器列表。如果 FPS 很高且一切处于最佳状态，这将显示 <code>- None</code>。</li></ul>',18)])])}const b=t(n,[["render",l]]);export{m as __pageData,b as default};
